// Generate high-fidelity mock data
function generateMockData() {
    let mockRegions = [];
    let mockHistory = {};

    // 1. Generate base values for each post office in each region
    regionNames.forEach((region, rIdx) => {
        let offices = postOfficesTemplate[region] || ["BC Trung TûÂm", "BC Chi NhûÀnh 1", "BC Chi NhûÀnh 2"];
        let rTotalStaff = 0;
        let rTotalCOD = 0;
        let rCODTuNop = 0;
        
        let postOfficesData = offices.map((officeName, oIdx) => {
            // Seed base numbers based on indices to ensure stable and realistic diversity
            let staffCount = Math.floor(15 + ((rIdx * 7 + oIdx * 11) % 35)); // 15 to 50 staff
            let totalCOD = Math.floor(150 + ((rIdx * 13 + oIdx * 17) % 700)); // 150M to 850M VND
            
            // Base rate of self-depositing COD (e.g. from 35% to 92%)
            let baseRate = 35 + ((rIdx * 19 + oIdx * 23) % 55); 
            // Add some specific high or low performers for operational interest
            if (rIdx === 0 && oIdx === 0) baseRate = 96; // Superstar in Top region
            if (rIdx === 9 && oIdx === 2) baseRate = 28; // Big bottleneck in underperforming region
            
            let codTuNop = Math.round(totalCOD * (baseRate / 100));

            rTotalStaff += staffCount;
            rTotalCOD += totalCOD;
            rCODTuNop += codTuNop;

            return {
                TenBuuCuc: officeName,
                SoNVPTTT: staffCount,
                TongCOD: totalCOD, // Unit: Million VND
                CODTuNop: codTuNop,
                TyLeTuNop: Math.round((codTuNop / totalCOD) * 1000) / 10
            };
        });

        let regionRate = Math.round((rCODTuNop / rTotalCOD) * 1000) / 10;
        
        // Yesterday's rate for trend (+/-)
        let yesterdayRate = regionRate - (-2 + ((rIdx * 7) % 5)); // Diff of -2% to +3%
        yesterdayRate = Math.max(10, Math.min(100, Math.round(yesterdayRate * 10) / 10));
        let trend = Math.round((regionRate - yesterdayRate) * 10) / 10;

        mockRegions.push({
            TenVung: region,
            SoNVPTTT: rTotalStaff,
            TongCOD: rTotalCOD,
            CODTuNop: rCODTuNop,
            TyLeTuNop: regionRate,
            Trend: trend,
            BuuCucList: postOfficesData
        });
    });

    // 2. Generate 14-day history for the line chart (trending upwards generally)
    dateRange.forEach((date, dIdx) => {
        mockHistory[date] = regionNames.map((region, rIdx) => {
            // Find base rate from current values
            let currentRegion = mockRegions.find(r => r.TenVung === region);
            let finalRate = currentRegion.TyLeTuNop;
            
            // Generate historical progress (going upwards with slight noise as we go forward in time)
            let factor = (dIdx - (dateRange.length - 1)) * (0.8 + ((rIdx * 3) % 2) * 0.4); // e.g. -13 to 0 * factor
            let histRate = finalRate + factor + (Math.sin(dIdx + rIdx) * 1.5);
            histRate = Math.max(15, Math.min(100, Math.round(histRate * 10) / 10));

            return {
                TenVung: region,
                TyLeTuNop: histRate
            };
        });
    });

    return {
        regions: mockRegions,
        history: mockHistory
    };
}

