// Drag and drop Excel importer using SheetJS
function setupExcelImport() {
    let dropZone = document.getElementById('drop-zone');
    let fileInput = document.getElementById('excel-file-input');

    // Make dropZone trigger file input
    dropZone.addEventListener('click', () => fileInput.click());

    // Highlight dropZone on drag events
    ['dragenter', 'dragover'].forEach(eventName => {
        dropZone.addEventListener(eventName, (e) => {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.add('dragover');
        }, false);
    });

    ['dragleave', 'drop'].forEach(eventName => {
        dropZone.addEventListener(eventName, (e) => {
            e.preventDefault();
            e.stopPropagation();
            dropZone.classList.remove('dragover');
        }, false);
    });

    // Handle dropped files
    dropZone.addEventListener('drop', (e) => {
        let dt = e.dataTransfer;
        let files = dt.files;
        if (files.length) {
            handleExcelFile(files[0]);
        }
    });

    // Handle selected files
    fileInput.addEventListener('change', (e) => {
        if (e.target.files.length) {
            handleExcelFile(e.target.files[0]);
        }
    });
}

function handleExcelFile(file) {
    if (!file.name.endsWith('.xlsx') && !file.name.endsWith('.xls') && !file.name.endsWith('.csv')) {
        alert("Vui lûýng chÃ£ tÃ¤Èi lûˆn tÃ£p Excel (.xlsx, .xls) hoÃ¤ñc CSV!");
        return;
    }

    let reader = new FileReader();
    reader.onload = function(e) {
        try {
            let data = new Uint8Array(e.target.result);
            let workbook = XLSX.read(data, {type: 'array'});
            
            // Assume the first sheet is the operational sheet
            let sheetName = workbook.SheetNames[0];
            let worksheet = workbook.Sheets[sheetName];
            let json = XLSX.utils.sheet_to_json(worksheet);

            if (json.length === 0) {
                alert("TÃ£p Excel rÃ£ng hoÃ¤ñc áÃ£nh dÃ¤Àng khûÇng áû¤ng!");
                return;
            }

            // Verify headers
            let requiredHeaders = ['Ngay', 'Vung', 'BuuCuc', 'SoNVPTTT', 'TongCOD', 'CODTuNop'];
            let excelHeaders = Object.keys(json[0]);
            
            // Check if essential headers exist (with some fuzzy matching support)
            let hasHeaders = requiredHeaders.every(req => {
                return excelHeaders.some(ex => ex.toLowerCase().replace(/[^a-z]/g, '').includes(req.toLowerCase()));
            });

            if (!hasHeaders) {
                alert(`CÃ¤Ëu trû¤c cÃ£t khûÇng hÃ£Èp lÃ£! File cÃ¤Ïn chÃ£ˋa cûÀc cÃ£t chûÙnh:\n- Ngay (Ngû y)\n- Vung (Vû¿ng)\n- BuuCuc (Bó¯u CÃ£Ëc)\n- SoNVPTTT (SÃ£ NVPTTT)\n- TongCOD (TÃ£ng COD)\n- CODTuNop (COD TÃ£Ý NÃ£p)`);
                return;
            }

            // Parse and format the excel JSON to appData state
            processImportedJSON(json);
            
            alert("TÃ¤Èi lûˆn dÃ£₤ liÃ£u mÃ£i thû nh cûÇng!");
            saveDataToLocalStorage();
            renderDashboard();
            renderCharts();
        } catch (err) {
            console.error(err);
            alert("áûÈ xÃ¤Èy ra lÃ£i khi áÃ£c tÃ£p Excel. Vui lûýng kiÃ£m tra lÃ¤Ài cÃ¤Ëu trû¤c file!");
        }
    };
    reader.readAsArrayBuffer(file);
}

// Convert parsed Excel rows into structured appData
function processImportedJSON(rows) {
    // 1. Group data by Vung and BuuCuc to construct the current regions array
    let regionsMap = {};
    let uniqueDatesSet = new Set();

    rows.forEach(row => {
        // Map columns with fuzzy key matching
        let dateVal = row['Ngay'] || row['Ngû y'] || '22/05/2026';
        let regionName = row['Vung'] || row['Vû¿ng'] || 'Vû¿ng Chó¯a PhûÂn LoÃ¤Ài';
        let officeName = row['BuuCuc'] || row['Bó¯u CÃ£Ëc'] || row['Bó¯u cÃ£Ëc'] || 'BC Trung TûÂm';
        let staff = parseInt(row['SoNVPTTT'] || row['SÃ£ NVPTTT'] || 0);
        let tongCod = parseFloat(row['TongCOD'] || row['TÃ£ng COD'] || 0);
        let codTuNop = parseFloat(row['CODTuNop'] || row['COD TÃ£Ý NÃ£p'] || row['COD tÃ£Ý nÃ£p'] || 0);

        uniqueDatesSet.add(dateVal);

        // We use the latest date in the excel row list as our "current" active date
        if (!regionsMap[regionName]) {
            regionsMap[regionName] = {
                TenVung: regionName,
                SoNVPTTT: 0,
                TongCOD: 0,
                CODTuNop: 0,
                TyLeTuNop: 0,
                Trend: 0,
                BuuCucList: {}
            };
        }

        let region = regionsMap[regionName];
        
        if (!region.BuuCucList[officeName]) {
            region.BuuCucList[officeName] = {
                TenBuuCuc: officeName,
                SoNVPTTT: staff,
                TongCOD: tongCod,
                CODTuNop: codTuNop,
                TyLeTuNop: tongCod > 0 ? Math.round((codTuNop / tongCod) * 1000) / 10 : 0
            };
        } else {
            // Accumulate if there are multiple entries
            region.BuuCucList[officeName].SoNVPTTT += staff;
            region.BuuCucList[officeName].TongCOD += tongCod;
            region.BuuCucList[officeName].CODTuNop += codTuNop;
            region.BuuCucList[officeName].TyLeTuNop = region.BuuCucList[officeName].TongCOD > 0 ? 
                Math.round((region.BuuCucList[officeName].CODTuNop / region.BuuCucList[officeName].TongCOD) * 1000) / 10 : 0;
        }
    });

    // 2. Format regionsMap into final regions array structure
    let finalRegions = [];
    Object.keys(regionsMap).forEach(rName => {
        let reg = regionsMap[rName];
        let rStaff = 0;
        let rTongCod = 0;
        let rCodTuNop = 0;
        
        let officesList = Object.keys(reg.BuuCucList).map(oName => {
            let o = reg.BuuCucList[oName];
            rStaff += o.SoNVPTTT;
            rTongCod += o.TongCOD;
            rCodTuNop += o.CODTuNop;
            return o;
        });

        let currentRate = rTongCod > 0 ? Math.round((rCodTuNop / rTongCod) * 1000) / 10 : 0;
        
        // Randomly simulate a realistic trend since yesterday
        let trend = Math.round((-1.5 + Math.random() * 4.5) * 10) / 10; 

        finalRegions.push({
            TenVung: rName,
            SoNVPTTT: rStaff,
            TongCOD: rTongCod,
            CODTuNop: rCodTuNop,
            TyLeTuNop: currentRate,
            Trend: trend,
            BuuCucList: officesList
        });
    });

    appData.regions = finalRegions;

    // 3. Generate history dates from the list of dates in the Excel
    let datesList = Array.from(uniqueDatesSet).sort();
    if (datesList.length > 1) {
        appData.selectedDate = datesList[datesList.length - 1]; // Set current date as the latest
        
        // Populate historical trend using Excel rows matching each day
        let newHistory = {};
        datesList.forEach(date => {
            let dateRows = rows.filter(r => (r['Ngay'] || r['Ngû y'] || '') === date);
            
            // Aggregate by region for this specific date
            let regionAgg = {};
            dateRows.forEach(row => {
                let regionName = row['Vung'] || row['Vû¿ng'] || 'Vû¿ng Chó¯a PhûÂn LoÃ¤Ài';
                let tongCod = parseFloat(row['TongCOD'] || row['TÃ£ng COD'] || 0);
                let codTuNop = parseFloat(row['CODTuNop'] || row['COD TÃ£Ý NÃ£p'] || 0);

                if (!regionAgg[regionName]) {
                    regionAgg[regionName] = { cod: 0, self: 0 };
                }
                regionAgg[regionName].cod += tongCod;
                regionAgg[regionName].self += codTuNop;
            });

            newHistory[date] = Object.keys(regionAgg).map(rName => {
                let agg = regionAgg[rName];
                return {
                    TenVung: rName,
                    TyLeTuNop: agg.cod > 0 ? Math.round((agg.self / agg.cod) * 1000) / 10 : 0
                };
            });
        });
        appData.history = newHistory;
    }
}

// Generate and trigger download of a sample CSV/Excel layout
function exportSampleExcel() {
    // We create a simple, neat mockup dataset in JSON
    let sampleRows = [];
    
    // Generate dates: past 3 days for sample size
    const sampleDates = ['20/05/2026', '21/05/2026', '22/05/2026'];
    
    sampleDates.forEach(date => {
        // Let's add 5 major regions with 2 post offices each to keep sample clean and clear
        const sampleRegions = ["Vû¿ng áûÇng Nam BÃ£", "Vû¿ng TP.HCM Trung TûÂm", "Vû¿ng Hû  NÃ£i NÃ£i Thû nh", "Vû¿ng TûÂy Nguyûˆn", "Vû¿ng TûÂy Nam BÃ£"];
        
        sampleRegions.forEach((region, rIdx) => {
            const offices = region === "Vû¿ng TP.HCM Trung TûÂm" ? ["BC QuÃ¤Ùn 1", "BC Bû˜nh ThÃ¤Ành"] : ["BC Chi NhûÀnh A", "BC Chi NhûÀnh B"];
            
            offices.forEach((office, oIdx) => {
                let staff = 20 + oIdx * 5 + rIdx;
                let cod = 250 + oIdx * 100 + rIdx * 50;
                // Calculate self-deposit COD with some random variations
                let rate = 45 + (rIdx * 8) + (oIdx * 12);
                rate = Math.min(95, rate);
                let selfCod = Math.round(cod * (rate / 100));

                sampleRows.push({
                    "Ngû y": date,
                    "Vû¿ng": region,
                    "Bó¯u CÃ£Ëc": office,
                    "SÃ£ NVPTTT": staff,
                    "TÃ£ng COD (triÃ£u VND)": cod,
                    "COD TÃ£Ý NÃ£p (triÃ£u VND)": selfCod
                });
            });
        });
    });

    // Create Excel Workbook
    let wb = XLSX.utils.book_new();
    let ws = XLSX.utils.json_to_sheet(sampleRows);
    
    XLSX.utils.book_append_sheet(wb, ws, "DÃ£₤ liÃ£u mÃ¤¨u nÃ£p COD");
    
    // Download File
    XLSX.writeFile(wb, "mau_bao_cao_tu_nop_cod.xlsx");
}

// Utility Helpers
function formatCurrency(val) {
    // Format to Millions VND, rounded
    return val.toLocaleString('vi-VN');
}

